// Node 7 — Validate & Enforce Safety (v4 - Fixed & Flexible)
// Mode: Run Once for All Items
// Output: [{ json: { decision, commentary, agentDecision, orders, metrics, warnings, ctx } }]

function isObj(x) {
  return x && typeof x === "object" && !Array.isArray(x);
}

function safeJsonParse(s) {
  try { return JSON.parse(s); } catch { return null; }
}

function toNumOrNull(x) {
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

function clampText(s, n) {
  return String(s ?? "").replace(/\s+/g, " ").trim().slice(0, n);
}

function normSymbol(v) {
  return String(v ?? "").trim();
}

function uniq(arr) {
  return Array.from(new Set((arr || []).filter(Boolean)));
}

function deepClone(obj) {
  try { return JSON.parse(JSON.stringify(obj)); } catch { return obj; }
}

function pickFirstRelevantInput(all) {
  for (const it of all) {
    const j = it?.json ?? {};
    if (j.portfolioSummary || j.portfolioRows) return j;
  }
  return all[0]?.json ?? {};
}

function extractNewsItems(input) {
  const candidates = [
    input?.market?.newsItems,
    input?.market?.marketNewsPack?.newsItems,
    input?.market?.marketNewsPack?.topItems,
    input?.market?.marketNewsPack?.items,
    input?.marketNewsPack?.newsItems,
    input?.marketNewsPack?.topItems,
    input?.marketNewsPack?.items,
    input?.newsItems,
    input?.news,
    input?.market?.news,
  ];

  for (const c of candidates) {
    if (Array.isArray(c) && c.length) return c;
  }
  return [];
}

function getPortfolioPositionsSymbols(portfolioSummary) {
  const pos = Array.isArray(portfolioSummary?.positions) ? portfolioSummary.positions : [];
  return uniq(
    pos
      .map((p) => normSymbol(p.Symbol ?? p.symbol))
      .filter((s) => s && s !== "CASH_EUR" && s !== "__META__")
  );
}

function buildPricesFallbackFromPortfolio(portfolioSummary) {
  const pricesFallback = {};
  const posArr = Array.isArray(portfolioSummary?.positions) ? portfolioSummary.positions : [];

  for (const p of posArr) {
    const s = normSymbol(p.Symbol ?? p.symbol);
    if (!s || s === "CASH_EUR" || s === "__META__") continue;

    let last = Number(p.LastPrice ?? NaN);
    if (!Number.isFinite(last) || last <= 0) {
      const q = Number(p.Quantity ?? NaN);
      const mv = Number(p.MarketValue ?? NaN);
      if (Number.isFinite(q) && q > 0 && Number.isFinite(mv)) last = mv / q;
    }

    if (Number.isFinite(last) && last > 0) {
      pricesFallback[s] = {
        lastPrice: last,
        source: "portfolio_lastPrice",
        ts: String(p.UpdatedAt ?? ""),
        stale: false,
      };
    }
  }
  return pricesFallback;
}

function extractAgentDecisionObject(input) {
  if (isObj(input.output) && (
    Array.isArray(input.output.actions) ||
    isObj(input.output.portfolioPlan) ||
    isObj(input.output.decisionMeta)
  )) {
    return { ...input.output, _parseStatus: "OK_OBJECT_OUTPUT" };
  }

  if (isObj(input.agentDecision)) {
    return { ...input.agentDecision, _parseStatus: "OK_AGENTDECISION" };
  }

  const msg0 = Array.isArray(input.output) ? input.output[0] : null;
  const content0 = msg0 && Array.isArray(msg0.content) ? msg0.content[0] : null;

  let decisionRaw = content0?.text ?? content0?.text?.text ?? null;

  if (isObj(decisionRaw)) return { ...decisionRaw, _parseStatus: "OK_OPENAI_OBJECT" };

  if (typeof decisionRaw === "string") {
    const parsed = safeJsonParse(decisionRaw);
    if (isObj(parsed)) return { ...parsed, _parseStatus: "OK_OPENAI_TEXT_JSON" };
    return { _rawText: decisionRaw, _parseStatus: "TEXT_NOT_JSON" };
  }

  if (decisionRaw == null) {
    return { _parseStatus: "MISSING_DECISION", _why: "No decision payload found." };
  }

  return { _rawValue: decisionRaw, _parseStatus: "UNEXPECTED_TYPE" };
}

function coerceAgentDecisionToExpectedShape(agentDecision) {
  if (!isObj(agentDecision)) return { _parseStatus: "NOT_OBJECT", actions: [], dataCaveats: [], backfillRequests: [] };
  const d = deepClone(agentDecision);
  if (!Array.isArray(d.actions)) d.actions = [];
  if (!Array.isArray(d.dataCaveats)) d.dataCaveats = [];
  if (!Array.isArray(d.backfillRequests)) d.backfillRequests = [];
  return d;
}

function computeTotalPortfolioValueEUR(portfolioSummary, prices) {
  const explicit = Number(
    portfolioSummary?.totalPortfolioValueEUR ??
    portfolioSummary?.totalValueEUR ??
    NaN
  );
  if (Number.isFinite(explicit) && explicit > 0) return explicit;

  const cash = Number(portfolioSummary?.cashEUR ?? 0);
  const posArr = Array.isArray(portfolioSummary?.positions) ? portfolioSummary.positions : [];
  let equity = 0;

  for (const p of posArr) {
    const s = normSymbol(p.Symbol ?? p.symbol);
    if (!s || s === "CASH_EUR" || s === "__META__") continue;

    const q = Number(p.Quantity ?? 0);
    if (!Number.isFinite(q) || q === 0) continue;

    const last = Number(prices?.[s]?.lastPrice ?? p.LastPrice ?? NaN);
    if (Number.isFinite(last) && last > 0) equity += q * last;
    else {
      const mv = Number(p.MarketValue ?? NaN);
      if (Number.isFinite(mv)) equity += mv;
    }
  }
  return cash + equity;
}

function buildHoldingsMap(portfolioSummary, prices) {
  const map = {};
  const posArr = Array.isArray(portfolioSummary?.positions) ? portfolioSummary.positions : [];

  for (const p of posArr) {
    const s = normSymbol(p.Symbol ?? p.symbol);
    if (!s || s === "CASH_EUR" || s === "__META__") continue;

    const qty = Number(p.Quantity ?? 0);
    const last = Number(prices?.[s]?.lastPrice ?? p.LastPrice ?? NaN);

    map[s] = {
      Symbol: s,
      Quantity: Number.isFinite(qty) ? qty : 0,
      LastPrice: Number.isFinite(last) ? last : null,
    };
  }
  return map;
}

function generateOrdersFromActions(agentDecision, portfolioSummary, prices, feesConfig, rmCfg) {
  const warnings = [];
  const ordersSell = [];
  const ordersBuy = [];

  const actions = Array.isArray(agentDecision?.actions) ? agentDecision.actions : [];
  const holdings = buildHoldingsMap(portfolioSummary, prices);

  const totalValue = computeTotalPortfolioValueEUR(portfolioSummary, prices);
  if (!Number.isFinite(totalValue) || totalValue <= 0) {
    warnings.push("PORTFOLIO_VALUE_INVALID: cannot size orders.");
    return { orders: [], warnings };
  }

  let cashSim = Number(portfolioSummary?.cashEUR ?? 0);
  const fixed = Number(feesConfig?.orderFeeFixedEUR ?? 0);
  const pct = Number(feesConfig?.orderFeePct ?? 0);

  const currentNotional = (sym) => {
    const h = holdings[sym];
    if (!h) return 0;
    const px = Number(prices?.[sym]?.lastPrice ?? h.LastPrice ?? NaN);
    if (!Number.isFinite(px) || px <= 0) return 0;
    return h.Quantity * px;
  };

  for (const a of actions) {
    const sym = normSymbol(a?.symbol);
    const act = String(a?.action ?? "").toUpperCase();
    if (!sym) continue;
    if (!["OPEN", "INCREASE", "DECREASE", "CLOSE"].includes(act)) continue;

    const px = Number(prices?.[sym]?.lastPrice ?? NaN);
    if (!Number.isFinite(px) || px <= 0) {
      warnings.push(`SKIP_NO_PRICE:${sym}:${act}`);
      continue;
    }

    const currNotional = currentNotional(sym);
    const targetNotionalExplicit = toNumOrNull(a?.targetNotionalEUR ?? a?.targetNotional ?? null);

    let targetNotional = null;
    if (act === "CLOSE") targetNotional = 0;
    else if (targetNotionalExplicit != null) targetNotional = targetNotionalExplicit;
    else if (a?.targetWeightPct != null) targetNotional = (Number(a.targetWeightPct) / 100) * totalValue;

    // Common extras
    const horizonDays = toNumOrNull(a?.horizonDays);
    const entryPlan = isObj(a?.entryPlan) ? a.entryPlan : {};
    const riskPlan = isObj(a?.riskPlan) ? a.riskPlan : {};

    if (targetNotional == null) {
        warnings.push(`SKIP_NO_TARGET:${sym}:${act}`);
        continue;
    }

    // Processing Logic
    if (act === "DECREASE" || act === "CLOSE") {
       const sellNotional = currNotional - targetNotional;
       if (sellNotional > 0) {
         const qtyToSell = Math.ceil(sellNotional / px);
         ordersSell.push({
            symbol: sym, side: "SELL", quantity: qtyToSell, price: null,
            rationale: clampText(a?.rationale, 240),
            orderType: String(entryPlan.orderType || "MARKET"),
            limitPrice: toNumOrNull(entryPlan.limitPrice),
            stopLossPct: toNumOrNull(riskPlan.stopLossPct),
            confidence: a?.confidence,
            priority: a?.priority
         });
       }
    }

    if (act === "OPEN" || act === "INCREASE") {
        const buyNotional = targetNotional - currNotional;
        if (buyNotional > 0) {
            const qtyToBuy = Math.floor(buyNotional / px);
            if (qtyToBuy >= 1) {
                ordersBuy.push({
                    symbol: sym, side: "BUY", quantity: qtyToBuy, price: null,
                    rationale: clampText(a?.rationale, 240),
                    orderType: String(entryPlan.orderType || "MARKET"),
                    limitPrice: toNumOrNull(entryPlan.limitPrice),
                    stopLossPct: toNumOrNull(riskPlan.stopLossPct),
                    confidence: a?.confidence,
                    priority: a?.priority
                });
            }
        }
    }
  }

  // Execution simulation
  const finalOrders = [];

  // Sells first to raise cash
  for (const o of ordersSell) {
    finalOrders.push(o);
    const px = Number(prices?.[o.symbol]?.lastPrice ?? NaN);
    if (Number.isFinite(px)) {
        const proceeds = (o.quantity * px) * (1 - pct) - fixed;
        cashSim += proceeds;
    }
  }

  // Buys if cash available
  for (const o of ordersBuy) {
    const px = Number(prices?.[o.symbol]?.lastPrice ?? NaN);
    if (Number.isFinite(px)) {
        const cost = (o.quantity * px) * (1 + pct) + fixed;
        if (cashSim >= cost) {
            finalOrders.push(o);
            cashSim -= cost;
        } else {
            warnings.push(`SKIP_INSUFFICIENT_CASH:${o.symbol}`);
        }
    }
  }

  return { orders: finalOrders, warnings };
}

function estimateFeesEUR(orders, feesConfig, prices) {
  const fixed = Number(feesConfig?.orderFeeFixedEUR ?? 0);
  const pct = Number(feesConfig?.orderFeePct ?? 0);
  let total = 0;

  for (const o of orders) {
    const s = normSymbol(o.symbol);
    const q = Number(o.quantity ?? NaN);
    if (!s || !Number.isFinite(q) || q <= 0) continue;
    const px = Number(o.price ?? prices?.[s]?.lastPrice ?? NaN);
    if (!Number.isFinite(px) || px <= 0) continue;
    total += fixed + pct * (q * px);
  }
  return total;
}

// ------------------- MAIN -------------------

const all = $input.all();
const input = pickFirstRelevantInput(all);

const now = new Date();
const ts = now.toISOString();

const portfolioSummary = input.portfolioSummary ?? input.ctx?.portfolioSummary ?? { cashEUR: 0, positions: [] };
const meta0 = input.meta ?? input.ctx?.meta ?? {};
const feesConfig = input.feesConfig ?? input.ctx?.feesConfig ?? { orderFeeFixedEUR: 0, orderFeePct: 0 };
const market0 = input.market ?? input.ctx?.market ?? {};
const upstreamPrices = isObj(market0.prices) ? market0.prices : {};
const upstreamNewsItems = extractNewsItems(input);

// Agent decision parsing
let agentDecision = extractAgentDecisionObject(input);
agentDecision = coerceAgentDecisionToExpectedShape(agentDecision);

// Prices merge (fallback from portfolio)
const pricesFallback = buildPricesFallbackFromPortfolio(portfolioSummary);
const mergedPrices = { ...pricesFallback, ...upstreamPrices };

// --- PATCH : INJECT LIMIT PRICES AS PROXY ---
const injectedPrices = [];
if (Array.isArray(agentDecision.actions)) {
    for (const action of agentDecision.actions) {
        const sym = normSymbol(action.symbol);
        const limit = toNumOrNull(action.entryPlan?.limitPrice);

        // Si on veut trader et qu'on n'a pas de prix marché, mais qu'on a une limite agent
        if (sym && limit && limit > 0) {
            const currentPrice = mergedPrices[sym]?.lastPrice;
            if (!currentPrice) {
                mergedPrices[sym] = {
                    lastPrice: limit,
                    source: "agent_limit_proxy",
                    stale: false
                };
                injectedPrices.push(sym);
            }
        }
    }
}
// --------------------------------------------

// Universe + coverage check
const heldSymbols = getPortfolioPositionsSymbols(portfolioSummary);
const tradeSymbols = uniq(
  (Array.isArray(agentDecision?.actions) ? agentDecision.actions : [])
    .filter((a) => ["OPEN", "INCREASE", "DECREASE", "CLOSE"].includes(String(a?.action ?? "").toUpperCase()))
    .map((a) => normSymbol(a?.symbol))
);

const universe = uniq([...heldSymbols, ...tradeSymbols]);

let pricedForRequested = 0;
const missingRequested = [];
for (const s of tradeSymbols) {
  const px = Number(mergedPrices?.[s]?.lastPrice ?? NaN);
  if (Number.isFinite(px) && px > 0) pricedForRequested += 1;
  else missingRequested.push(s);
}

// Safety definition
const okForTrading = tradeSymbols.length ? (pricedForRequested === tradeSymbols.length) : true;
const rmCfg = input.config?.riskManager ?? input.ctx?.config?.riskManager ?? {};

// Generate orders
let { orders, warnings: orderWarnings } = generateOrdersFromActions(
  agentDecision,
  portfolioSummary,
  mergedPrices, // Now contains injected limit prices
  feesConfig,
  rmCfg
);

// --- WARNINGS AGGREGATION (Fixed ReferenceError) ---
const warnings = [];

// Safety Veto (should not trigger if patch worked)
const safetyWarnings = [];
if (!okForTrading) {
  if (tradeSymbols.length) {
    safetyWarnings.push(`SAFETY_VETO_MISSING_PRICES:${missingRequested.join(",")}`);
    orders = [];
  }
}

if (injectedPrices.length > 0) {
    safetyWarnings.push(`NOTICE: Used agent limit price as proxy for: ${injectedPrices.join(", ")}`);
}

// Parse problems
if (agentDecision?._parseStatus && !String(agentDecision._parseStatus).startsWith("OK")) {
  warnings.push(`AGENT_DECISION_PARSE:${agentDecision._parseStatus}`);
  if (agentDecision?._why) warnings.push(`AGENT_DECISION_PARSE_WHY:${agentDecision._why}`);
}

// Carry caveats
if (Array.isArray(agentDecision?.dataCaveats)) {
  for (const c of agentDecision.dataCaveats) warnings.push(String(c));
}

// Missing prices for held positions (informational)
for (const s of heldSymbols) {
  const px = Number(mergedPrices?.[s]?.lastPrice ?? NaN);
  if (!Number.isFinite(px) || px <= 0) warnings.push(`MISSING_PRICE_FOR_HELD:${s}`);
}

// Add order & safety warnings
for (const w of orderWarnings) warnings.push(String(w));
for (const w of safetyWarnings) warnings.push(String(w));
// ---------------------------------------------------

// Metrics
const aiCostEUR = Number(input?.metrics?.aiCostEUR ?? 0);
const expectedFeesEUR = estimateFeesEUR(orders, feesConfig, mergedPrices);

const decision = orders.length ? "TRADE" : "NO_TRADE";

const ctx = {
  sheetId: input.sheetId,
  run: { timestampParis: ts, model: "gpt-5.2" },
  portfolioSummary,
  market: { prices: mergedPrices }
};

const cash0 = Number(portfolioSummary?.cashEUR ?? 0);
const actionsCount = Array.isArray(agentDecision?.actions) ? agentDecision.actions.length : 0;
const caveatsCount = Array.isArray(agentDecision?.dataCaveats) ? agentDecision.dataCaveats.length : 0;

const commentary = `PM_DECISION=${decision} | orders=${orders.length} | actions=${actionsCount} | cash0=${cash0} | caveats=${caveatsCount}`;

return [{
  json: {
    decision,
    commentary,
    agentDecision,
    orders,
    metrics: {
        aiCostEUR: Number.isFinite(aiCostEUR) ? aiCostEUR : 0,
        expectedFeesEUR: Number.isFinite(expectedFeesEUR) ? expectedFeesEUR : 0,
    },
    warnings,
    ctx,
  },
}];

// Node 8 — Simulate & Build Sheet Rows (v8 Verified)
// Fonctionnalités : Simulation Trade, Calcul Portfolio, NextReviewDate
// Nettoyage : Plus de gestion de 'Notes' ni d'écriture auto sur '__META__'

function normSymbol(v) { return String(v ?? "").trim(); }

// Récupération intelligente du prix (Marché > Portefeuille > LimitOrder)
function getPriceFallback(symbol, ctx) {
  const s = normSymbol(symbol);
  if (!s) return NaN;
  const prices = ctx?.market?.prices ?? {};
  const p0 = Number(prices?.[s]?.lastPrice);
  if (Number.isFinite(p0) && p0 > 0) return p0;

  const posArr = Array.isArray(ctx?.portfolioSummary?.positions) ? ctx.portfolioSummary.positions : [];
  const p = posArr.find((r) => normSymbol(r.Symbol ?? r.symbol) === s);
  if (p) {
    const last = Number(p.LastPrice);
    if (Number.isFinite(last) && last > 0) return last;
  }
  return NaN;
}

// Calcul de date future
function addDays(date, days) {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}

// --- INITIALISATION ---
const decisionObj = $json;
const ctx = decisionObj.ctx || {};
const ts = (ctx?.run?.timestampParis && String(ctx.run.timestampParis)) || new Date().toISOString();
const orders = Array.isArray(decisionObj.orders) ? decisionObj.orders : [];
const actions = Array.isArray(decisionObj.agentDecision?.actions) ? decisionObj.agentDecision.actions : [];

const cash0 = Number(ctx?.portfolioSummary?.cashEUR ?? 0);
const positions0 = Array.isArray(ctx?.portfolioSummary?.positions) ? ctx.portfolioSummary.positions : [];
const meta0 = ctx?.meta ?? {}; 
const orderFeeFixedEUR = Number(ctx?.feesConfig?.orderFeeFixedEUR ?? 0);
const orderFeePct = Number(ctx?.feesConfig?.orderFeePct ?? 0);
const aiCostThisRun = Number(decisionObj?.metrics?.aiCostEUR ?? 0);

// --- 1. CHARGEMENT DE L'ÉTAT ACTUEL ---
const holdings = {};
for (const p of positions0) {
  const s = normSymbol(p.Symbol ?? p.symbol);
  if (!s || s === "CASH_EUR" || s === "__META__") continue;
  holdings[s] = { 
      Symbol: s, 
      ISIN: p.ISIN, 
      Quantity: Number(p.Quantity), 
      AvgPrice: Number(p.AvgPrice), 
      NextReviewDate: p.NextReviewDate || "" 
  };
}

// --- 2. MISE À JOUR DES DATES DE REVUE (Mémoire Agent) ---
for (const action of actions) {
    const s = normSymbol(action.symbol);
    if (!s) continue;
    if (Number.isInteger(action.nextReviewDays) && action.nextReviewDays > 0) {
        const nextDate = addDays(new Date(), action.nextReviewDays);
        if (holdings[s]) {
            holdings[s].NextReviewDate = nextDate.toISOString();
        } 
    }
}

// --- 3. SIMULATION DES TRADES ---
let cash = cash0;
const txRows = [];
let cumFees = 0; // Frais de CE run uniquement (plus d'historique dans Notes)
let cumAiCost = 0;

if (aiCostThisRun > 0) {
  cumAiCost += aiCostThisRun;
  cash -= aiCostThisRun;
}

// Log du Run
txRows.push({
  Timestamp: ts, Symbol: "__RUN__", Side: String(decisionObj.decision ?? "NO_TRADE"),
  Quantity: "", Price: "", Notional: "", Fees: 0, AiCost: aiCostThisRun, CashImpact: -aiCostThisRun, RealizedPnL: 0,
  Rationale: String(decisionObj.commentary ?? "")
});

let tradesExecuted = 0;
for (const o of orders) {
  const symbol = normSymbol(o.symbol);
  const side = String(o.side ?? "").toUpperCase();
  const qtyRequested = Number(o.quantity ?? 0);

  if (!symbol || !["BUY", "SELL"].includes(side) || qtyRequested < 1) continue;

  let price = Number(o.price);
  if (!Number.isFinite(price) || price <= 0) price = getPriceFallback(symbol, ctx);
  if (!Number.isFinite(price) || price <= 0) price = Number(o.limitPrice);

  if (!Number.isFinite(price) || price <= 0) continue;

  let execQty = qtyRequested;

  // Création ligne si achat d'une nouvelle valeur
  if (!holdings[symbol]) {
      holdings[symbol] = { Symbol: symbol, ISIN: "", Quantity: 0, AvgPrice: 0, NextReviewDate: "" };
      const action = actions.find(a => normSymbol(a.symbol) === symbol);
      if (action && Number.isInteger(action.nextReviewDays)) {
          holdings[symbol].NextReviewDate = addDays(new Date(), action.nextReviewDays).toISOString();
      }
  }

  const h0 = holdings[symbol];
  const q0 = Number(h0.Quantity);

  if (side === "SELL") {
    execQty = Math.min(qtyRequested, q0);
    if (execQty < 1) continue; // Rien à vendre
  }

  const notional = execQty * price;
  const fees = orderFeeFixedEUR + orderFeePct * notional;
  let cashImpact = 0, realizedPnL = 0;

  if (side === "BUY") {
    cashImpact = -(notional + fees);
    cash += cashImpact;
    const newQty = q0 + execQty;
    const newAvg = ((q0 * h0.AvgPrice) + (execQty * price)) / newQty;
    holdings[symbol] = { ...h0, Quantity: newQty, AvgPrice: newAvg };
  } else {
    realizedPnL = (price - h0.AvgPrice) * execQty;
    cashImpact = notional - fees;
    cash += cashImpact;
    holdings[symbol] = { ...h0, Quantity: q0 - execQty };
  }
  cumFees += fees;

  txRows.push({
    Timestamp: ts, Symbol: symbol, Side: side, Quantity: execQty, Price: price,
    Notional: notional, Fees: fees, AiCost: 0, CashImpact: cashImpact, RealizedPnL: realizedPnL,
    Rationale: String(o.rationale ?? "")
  });
  tradesExecuted++;
}

// --- 4. PREPARATION SAUVEGARDE ---
const portfolioUpserts = [];
// Mise à jour du Cash
portfolioUpserts.push({ Symbol: "CASH_EUR", MarketValue: cash, UpdatedAt: ts });

// Mise à jour des positions (SANS META)
for (const [sym, h] of Object.entries(holdings)) {
  if (h.Quantity > 0) {
    let last = getPriceFallback(sym, ctx);
    if (!last && ctx.market?.prices?.[sym]?.lastPrice) last = Number(ctx.market.prices[sym].lastPrice);
    const mv = last ? h.Quantity * last : 0;

    portfolioUpserts.push({
      Symbol: sym, 
      ISIN: h.ISIN, 
      Quantity: h.Quantity, 
      AvgPrice: h.AvgPrice,
      LastPrice: last || "", 
      MarketValue: mv, 
      UnrealizedPnL: last ? (last - h.AvgPrice) * h.Quantity : 0,
      UpdatedAt: ts, 
      NextReviewDate: h.NextReviewDate || "" 
    });
  }
}

// --- 5. CALCUL PERFORMANCE ---
const equity = portfolioUpserts.filter(r => r.Symbol !== "CASH_EUR").reduce((a, b) => a + (b.MarketValue || 0), 0);
const totalVal = cash + equity;
const initCap = Number(meta0.initialCapitalEUR) || totalVal; // Lu depuis MarketValue dans Node 4B

return [{
  json: {
    sheetId: ctx?.sheetId, 
    txRows, 
    portfolioUpserts,
    performanceRow: { 
        Timestamp: ts, 
        Cash: cash, 
        Equity: equity, 
        TotalValue: totalVal, 
        TotalPnL: totalVal - initCap, 
        ROI: (totalVal - initCap)/initCap, 
        CumFees: cumFees, 
        TradesThisRun: tradesExecuted 
    },
    ctx, 
    originalInput: decisionObj
  }
}];

const first = $input.first().json;
const rows = Array.isArray(first.txRows) ? first.txRows : [];

return rows
  .filter(r => r && typeof r === 'object' && !Array.isArray(r))
  .map(r => ({ json: r }));

const first = $input.first().json;
const rows = Array.isArray(first.portfolioUpserts) ? first.portfolioUpserts : [];

return rows
  .filter(r => r && typeof r === 'object' && !Array.isArray(r))
  .map(r => ({ json: r }));

// 13 — To Performance Item (Cleaned)
const first = $input.first().json;
const row = first.performanceRow;

if (!row || typeof row !== 'object' || Array.isArray(row)) {
  throw new Error("performanceRow is missing or not an object");
}

// Fonction helper pour arrondir proprement
function round(num, decimals = 2) {
  if (num === null || num === undefined || num === "") return num;
  const n = Number(num);
  if (!Number.isFinite(n)) return num;

  const factor = Math.pow(10, decimals);
  // Ajout de Number.EPSILON pour gérer les cas limites de virgule flottante
  return Math.round((n + Number.EPSILON) * factor) / factor;
}

// Application des arrondis
