const cashPct = totalValueEUR ? cashEUR / totalValueEUR : 0;

const sorted = [...held].sort((a,b) => b.MarketValue - a.MarketValue);
const top1Pct = (totalValueEUR && sorted.length) ? sorted[0].MarketValue / totalValueEUR : 0;
