const hhmmss = `${parts.hour}${parts.minute}${parts.second}`;
const rand = Math.random().toString(16).slice(2, 10) + Math.random().toString(16).slice(2, 10);
const runId = `RUN_${yyyymmdd}_${hhmmss}_${executionId ?? rand}`;

return [
  {
    json: {
      ...cfg,
