{ "input": "AI.PA | AIR LIQUIDE | High Impact negative news scandal fraud profit warning downgrade last 7 days" }

{ "input": "AI.PA | AIR LIQUIDE | High Impact positive news earnings merger acquisition contract upgrade" }

