parameters.jsCode:
// BackfillRequests → Queue Rows (patched v2 stable RequestId)
// Mode: Run Once for Each Item
// Input: Node 7 output => { agentDecision, ctx, warnings, decision, commentary, metrics, orders }
// Output: items[] each = one row to append/update in Google Sheets

function normSymbol(v) {
  return String(v ?? "").trim();
}

function clampText(s, n) {
  return String(s ?? "").replace(/\s+/g, " ").trim().slice(0, n);
}

function uniq(arr) {
  return Array.from(new Set((arr || []).filter(Boolean)));
}

function stableRequestId(symbol, needsArr) {
  const needs = (Array.isArray(needsArr) ? needsArr : []).map(String).sort().join(",");
  return `BF|${symbol}|${needs}`; // stable across runs
}

const input = $json ?? {};
const agentDecision = input.agentDecision ?? {};
const ctx = input.ctx ?? {};
const run = ctx.run ?? {};

const ts = String(run.timestampParis || new Date().toISOString());
const runId =
  String(run.runId || "").trim() ||
  String(agentDecision?.decisionMeta?.run_id || "").trim() ||
  "";

const backfill = Array.isArray(agentDecision.backfillRequests)
  ? agentDecision.backfillRequests
  : [];

if (!backfill.length) return [];

// Portfolio symbols (to flag inPortfolio)
const positions = Array.isArray(ctx?.portfolioSummary?.positions) ? ctx.portfolioSummary.positions : [];
const heldSymbols = uniq(
  positions
    .map(p => normSymbol(p.Symbol ?? p.symbol))
    .filter(s => s && s !== "CASH_EUR" && s !== "__META__")
);
const heldSet = new Set(heldSymbols);

// Optional action hint (from agentDecision.actions)
const actions = Array.isArray(agentDecision.actions) ? agentDecision.actions : [];
const actionBySymbol = new Map();
for (const a of actions) {
  const s = normSymbol(a?.symbol);
  if (!s) continue;
  if (!actionBySymbol.has(s)) actionBySymbol.set(s, a);
}

// Dedupe within current payload
const seen = new Set();
const rows = [];

for (const r of backfill) {
  const symbol = normSymbol(r?.symbol);
  const needsArr = Array.isArray(r?.needs) ? r.needs.map(String) : [];
  const needs = uniq(needsArr).sort();

  if (!symbol || !needs.length) continue;

  const reqId = stableRequestId(symbol, needs);
  if (seen.has(reqId)) continue;
  seen.add(reqId);

  const inPortfolio = heldSet.has(symbol);
  const a = actionBySymbol.get(symbol);
  const actionHint = a ? String(a.action || "") : "";
  const priorityHint = a && Number.isFinite(Number(a.priority)) ? Number(a.priority) : "";

  // Simple severity heuristic
  let severity = "MEDIUM";
  if (inPortfolio && (needs.includes("PRICE") || needs.includes("NEWS") || needs.includes("TECHNICAL"))) severity = "HIGH";
  if (!inPortfolio && needs.length === 1 && needs[0] === "NOTE") severity = "LOW";

  rows.push({
    RequestId: reqId,
    RunId: runId || "",
    Timestamp: ts,
    Symbol: symbol,
    InPortfolio: inPortfolio ? "TRUE" : "FALSE",
    ActionHint: clampText(actionHint, 24),
    PriorityHint: priorityHint === "" ? "" : String(priorityHint),
    NeedsCSV: needs.join(","),
    Why: clampText(r?.why, 480),

    Status: "OPEN",      // OPEN | DONE | SKIP
    CompletedAt: "",
    ResponseJson: "",
    Notes: "",
    Severity: severity,  // HIGH | MEDIUM | LOW
  });
}

return rows.map(row => ({ json: row }));

// AG1.00 - Assemble Input Packs (clean + matrix pack support)
// Mode: Run Once for All Items

const incoming = $input.all();

const out = {
  run: null,
  portfolioBrief: null,
  sector_brief: "",
  opportunity_brief: "",
  opportunity_pack: null,
  opportunity_stats: null,
  matrix_thresholds: null,
};

function pickText(obj, keys) {
  for (const k of keys) {
    if (obj && typeof obj[k] === "string" && obj[k].trim()) return obj[k].trim();
  }
  return "";
}

function pickObject(obj, keys) {
  for (const k of keys) {
    if (obj && typeof obj[k] === "object" && obj[k] !== null) return obj[k];
  }
  return null;
}

for (const it of incoming) {
  const j = it.json || {};

  if (!out.run) out.run = pickObject(j, ["run", "Run", "decisionMeta", "meta"]);
  if (!out.portfolioBrief) out.portfolioBrief = pickObject(j, ["portfolioBrief", "PortfolioBrief"]);

  if (!out.sector_brief) {
    out.sector_brief = pickText(j, ["sector_brief", "sectorBrief", "sector", "sector_momentum"]);
  }
  if (!out.opportunity_brief) {
    out.opportunity_brief = pickText(j, ["opportunity_brief", "opportunityBrief", "opportunity", "matrix"]);
  }

  if (!out.opportunity_pack && j && typeof j.opportunity_pack === "object") {
    out.opportunity_pack = j.opportunity_pack;
  }
  if (!out.opportunity_stats && j && typeof j.opportunity_stats === "object") {
    out.opportunity_stats = j.opportunity_stats;
  }
  if (!out.matrix_thresholds && j && typeof j.matrix_thresholds === "object") {
    out.matrix_thresholds = j.matrix_thresholds;
  }

  if (!out.sector_brief) {
    out.sector_brief = pickText(j, ["text", "brief", "output"]);
  }
  if (!out.opportunity_brief) {
    out.opportunity_brief = pickText(j, ["text", "brief", "output"]);
  }
}

if (!out.run) out.run = {};
if (!out.portfolioBrief) out.portfolioBrief = {};
if (!out.sector_brief) out.sector_brief = "";
if (!out.opportunity_brief) out.opportunity_brief = "";
if (!out.opportunity_pack && out.opportunity_brief) {
  out.opportunity_pack = {
    generatedAt: new Date().toISOString(),
    rows: [],
    stats: out.opportunity_stats || {},
    thresholds: out.matrix_thresholds || {},
  };
}

out.__debug = {
  incomingItems: incoming.length,
  has_run: !!Object.keys(out.run).length,
  has_portfolioBrief: !!Object.keys(out.portfolioBrief).length,
  has_sector_brief: !!out.sector_brief,
  has_opportunity_brief: !!out.opportunity_brief,
  has_opportunity_pack: !!out.opportunity_pack,
};

return [{ json: out }];
